/** Parser for Assignment 1 */

import java.io.*;
import java.util.*;

/** Exception class for representing parsing errors. */
class ParseException extends RuntimeException {
  ParseException(String s) { super(s); }
}

/** A parser class for Jam.  Each program requires a separate parser object. */
class Parser {

  private Lexer in;

  Parser(Lexer i) {
    in = i;
  }

  Parser(Reader inputStream) { this(new Lexer(inputStream)); }

  Parser(String fileName) throws IOException { this(new FileReader(fileName)); }

  Lexer lexer() { return in; }

  /** Parses a Jam program which is simply an Exp, followed by EOF. */
  public AST parse() throws ParseException {
    AST result = parseExp();
    Token next = in.readToken();
    if (next != null) {
      throw new ParseException("Expected end of input but found: " + next);
    }
    return result;
  }

  /** Parses:
    *   <exp> ::= if <exp> then <exp> else <exp>
    *           | let <def>+ in <exp>
    *           | map <id-list> to <exp>
    *           | <term> { <binop> <term> }*  (left associatively!)
    */
  private AST parseExp() {
    Token t = in.peek();
    if (t == Lexer.IF) {
      return parseIf();
    } else if (t == Lexer.LET) {
      return parseLet();
    } else if (t == Lexer.MAP) {
      return parseMap();
    } else {
      return parseBinaryExp();
    }
  }

  /** Parses: if <exp> then <exp> else <exp> */
  private If parseIf() {
    in.readToken(); // consume 'if'
    AST test = parseExp();
    Token then = in.readToken();
    if (then != Lexer.THEN)
      throw new ParseException("Expected 'then' but got: " + then);
    AST conseq = parseExp();
    Token els = in.readToken();
    if (els != Lexer.ELSE)
      throw new ParseException("Expected 'else' but got: " + els);
    AST alt = parseExp();
    return new If(test, conseq, alt);
  }

  /** Parses: let <def>+ in <exp>
    *   <def> ::= <id> := <exp> ;
    */
  private Let parseLet() {
    in.readToken(); // consume 'let'
    List<Def> defs = new ArrayList<Def>();
    defs.add(parseDef()); // at least one def required
    while (in.peek() != Lexer.IN) {
      if (in.peek() == null)
        throw new ParseException("Expected 'in' but reached end of input");
      defs.add(parseDef());
    }
    in.readToken(); // consume 'in'
    AST body = parseExp();
    return new Let(defs.toArray(new Def[0]), body);
  }

  /** Parses: <id> := <exp> ; */
  private Def parseDef() {
    Token t = in.readToken();
    if (!(t instanceof Variable))
      throw new ParseException("Expected variable in definition but got: " + t);
    Variable v = (Variable) t;
    Token bind = in.readToken();
    if (bind != Lexer.BIND)
      throw new ParseException("Expected ':=' but got: " + bind);
    AST rhs = parseExp();
    Token semi = in.readToken();
    if (semi != SemiColon.ONLY)
      throw new ParseException("Expected ';' but got: " + semi);
    return new Def(v, rhs);
  }

  /** Parses: map <id-list> to <exp>
    *   <id-list> ::= { <id> { , <id> }* }
    */
  private Map parseMap() {
    in.readToken(); // consume 'map'
    Variable[] vars = parseIdList();
    Token to = in.readToken();
    if (to != Lexer.TO)
      throw new ParseException("Expected 'to' but got: " + to);
    AST body = parseExp();
    return new Map(vars, body);
  }

  /** Parses: { <id> { , <id> }* }  (possibly empty) */
  private Variable[] parseIdList() {
    if (!(in.peek() instanceof Variable)) {
      return new Variable[0];
    }
    List<Variable> vars = new ArrayList<Variable>();
    vars.add((Variable) in.readToken());
    while (in.peek() == Comma.ONLY) {
      in.readToken(); // consume ','
      Token next = in.readToken();
      if (!(next instanceof Variable))
        throw new ParseException("Expected variable in id list but got: " + next);
      vars.add((Variable) next);
    }
    return vars.toArray(new Variable[0]);
  }

  /** Parses: <term> { <binop> <term> }*  (left associative) */
  private AST parseBinaryExp() {
    AST left = parseTerm();
    while (true) {
      Token t = in.peek();
      if (t instanceof OpToken) {
        OpToken op = (OpToken) t;
        if (op.isBinOp()) {
          in.readToken(); // consume binop
          AST right = parseTerm();
          left = new BinOpApp(op.toBinOp(), left, right);
        } else {
          break;
        }
      } else {
        break;
      }
    }
    return left;
  }

  /** Parses:
    *   <term> ::= <unop> <term>
    *            | <factor> { ( <exp-list> ) }
    *            | <empty>
    *            | <int>
    *            | <bool>
    */
  private AST parseTerm() {
    Token t = in.peek();
    if (t == null)
      throw new ParseException("Unexpected end of input in term");

    // Unop Term
    if (t instanceof OpToken && ((OpToken) t).isUnOp()) {
      in.readToken();
      AST arg = parseTerm();
      return new UnOpApp(((OpToken) t).toUnOp(), arg);
    }

    // Int, Bool, Empty constants (cannot have function application)
    if (t instanceof IntConstant)   { in.readToken(); return (IntConstant) t; }
    if (t instanceof BoolConstant)  { in.readToken(); return (BoolConstant) t; }
    if (t instanceof EmptyConstant) { in.readToken(); return (EmptyConstant) t; }

    // Factor { ( ExpList ) }
    AST factor = parseFactor();
    if (in.peek() == LeftParen.ONLY) {
      in.readToken(); // consume '('
      AST[] args = parseExpList();
      Token rparen = in.readToken();
      if (rparen != RightParen.ONLY)
        throw new ParseException("Expected ')' but got: " + rparen);
      return new App(factor, args);
    }
    return factor;
  }

  /** Parses: ( <exp> ) | <prim> | <id> */
  private AST parseFactor() {
    Token t = in.readToken();
    if (t == null)
      throw new ParseException("Unexpected end of input in factor");

    if (t == LeftParen.ONLY) {
      AST exp = parseExp();
      Token rparen = in.readToken();
      if (rparen != RightParen.ONLY)
        throw new ParseException("Expected ')' but got: " + rparen);
      return exp;
    } else if (t instanceof PrimFun) {
      return (PrimFun) t;
    } else if (t instanceof Variable) {
      return (Variable) t;
    } else {
      throw new ParseException("Unexpected token: " + t);
    }
  }

  /** Parses: { <exp> { , <exp> }* }  (possibly empty) */
  private AST[] parseExpList() {
    if (in.peek() == RightParen.ONLY) {
      return new AST[0];
    }
    List<AST> args = new ArrayList<AST>();
    args.add(parseExp());
    while (in.peek() == Comma.ONLY) {
      in.readToken(); // consume ','
      args.add(parseExp());
    }
    return args.toArray(new AST[0]);
  }
}

import junit.framework.*;
import java.io.*;

public class AgentTest extends TestCase {

  public AgentTest(String name) {
    super(name);
  }

  private void check(String expected, String input) {
    Parser p = new Parser(new StringReader(input));
    assertEquals(expected, p.parse().toString());
  }

  private void checkError(String input) {
    try {
      Parser p = new Parser(new StringReader(input));
      p.parse();
      fail("Expected ParseException for: " + input);
    } catch (ParseException e) {
      // expected
    }
  }

  // --- Constants ---

  public void testIntConstant() {
    check("42", "42");
  }

  public void testBoolTrue() {
    check("true", "true");
  }

  public void testBoolFalse() {
    check("false", "false");
  }

  public void testEmptyConstant() {
    check("empty", "empty");
  }

  // --- Variables ---

  public void testVariable() {
    check("x", "x");
  }

  public void testVariableWithDigits() {
    check("x1", "x1");
  }

  // --- Primitive Functions ---

  public void testPrimFunFirst() {
    check("first", "first");
  }

  public void testPrimFunRest() {
    check("rest", "rest");
  }

  public void testPrimFunCons() {
    check("cons", "cons");
  }

  public void testPrimFunArity() {
    check("arity", "arity");
  }

  public void testPrimFunNumberQ() {
    check("number?", "number?");
  }

  public void testPrimFunFunctionQ() {
    check("function?", "function?");
  }

  public void testPrimFunListQ() {
    check("list?", "list?");
  }

  public void testPrimFunEmptyQ() {
    check("empty?", "empty?");
  }

  public void testPrimFunConsQ() {
    check("cons?", "cons?");
  }

  // --- Unary Operators ---

  public void testUnaryMinus() {
    check("- 5", "-5");
  }

  public void testUnaryPlus() {
    check("+ 5", "+5");
  }

  public void testUnaryNot() {
    check("~ true", "~true");
  }

  public void testUnaryChain() {
    check("- - x", "--x");
  }

  // --- Binary Operators ---

  public void testAdd() {
    check("(2 + 3)", "2+3");
  }

  public void testSubtract() {
    check("(5 - 2)", "5 - 2");
  }

  public void testMultiply() {
    check("(3 * 4)", "3*4");
  }

  public void testDivide() {
    check("(10 / 2)", "10/2");
  }

  public void testEquals() {
    check("(x = y)", "x = y");
  }

  public void testNotEquals() {
    check("(x != y)", "x != y");
  }

  public void testLessThan() {
    check("(x < y)", "x < y");
  }

  public void testGreaterThan() {
    check("(x > y)", "x > y");
  }

  public void testLessThanEquals() {
    check("(x <= y)", "x <= y");
  }

  public void testGreaterThanEquals() {
    check("(x >= y)", "x >= y");
  }

  public void testAnd() {
    check("(x & y)", "x & y");
  }

  public void testOr() {
    check("(x | y)", "x | y");
  }

  // --- Left Associativity ---

  public void testLeftAssocAdd() {
    check("((1 + 2) + 3)", "1 + 2 + 3");
  }

  public void testLeftAssocMixed() {
    check("((1 + 2) - 3)", "1 + 2 - 3");
  }

  public void testLeftAssocFour() {
    check("(((1 + 2) + 3) + 4)", "1 + 2 + 3 + 4");
  }

  // --- Parenthesized expressions ---

  public void testParenthesized() {
    check("(2 + 3)", "(2 + 3)");
  }

  public void testParenChangesAssoc() {
    check("(1 + (2 + 3))", "1 + (2 + 3)");
  }

  // --- Function Application ---

  public void testAppNoArgs() {
    check("f()", "f()");
  }

  public void testAppOneArg() {
    check("f(x)", "f(x)");
  }

  public void testAppTwoArgs() {
    check("f(x, y)", "f(x, y)");
  }

  public void testAppWithExp() {
    check("f((1 + 2))", "f(1+2)");
  }

  public void testNestedApp() {
    check("f(g(x))", "f(g(x))");
  }

  public void testPrimApp() {
    check("cons(1, empty)", "cons(1, empty)");
  }

  public void testFirstApp() {
    check("first(x)", "first(x)");
  }

  // --- If expression ---

  public void testIf() {
    check("if true then 1 else 0", "if true then 1 else 0");
  }

  public void testIfNested() {
    check("if (x = 0) then 1 else 2", "if x = 0 then 1 else 2");
  }

  public void testIfElseIsIf() {
    check("if true then 1 else if false then 2 else 3",
          "if true then 1 else if false then 2 else 3");
  }

  // --- Let expression ---

  public void testLetOneDef() {
    check("let x := 1; in x", "let x := 1; in x");
  }

  public void testLetTwoDefs() {
    check("let x := 1; y := 2; in (x + y)", "let x := 1; y := 2; in x + y");
  }

  public void testLetBodyIsIf() {
    check("let x := 1; in if (x = 0) then true else false",
          "let x := 1; in if x = 0 then true else false");
  }

  // --- Map expression ---

  public void testMapNoArgs() {
    check("map  to 1", "map to 1");
  }

  public void testMapOneArg() {
    check("map x to x", "map x to x");
  }

  public void testMapTwoArgs() {
    check("map x,y to (x + y)", "map x, y to x + y");
  }

  // --- Complex examples from instructions ---

  public void testComplexFromInstructions() {
    check("(f(x) + (x * 12))", "f(x) + (x * 12)");
  }

  // --- Error cases ---

  public void testErrorExtraToken() {
    checkError("1 2");
  }

  public void testErrorMissingThen() {
    checkError("if true 1 else 0");
  }

  public void testErrorMissingElse() {
    checkError("if true then 1");
  }

  public void testErrorMissingSemicolon() {
    checkError("let x := 1 in x");
  }

  public void testErrorMissingIn() {
    checkError("let x := 1;");
  }

  public void testErrorLetNoBindings() {
    checkError("let in x");
  }

  public void testErrorUnclosedParen() {
    checkError("(1 + 2");
  }

  public void testErrorBracket() {
    checkError("[1, 2]");
  }

  public void testErrorEmptyInput() {
    // empty input - parse returns null or throws
    try {
      Parser p = new Parser(new StringReader(""));
      AST result = p.parse();
      // some parsers return null for empty input - either is acceptable
    } catch (ParseException e) {
      // also acceptable
    }
  }
}

